/**
 * Static data loader. The CSV-derived JSON ships in /static/data/articles.json
 * (generated by `fakethirtyeight build-site-data`). We import it once and
 * memoize derived indexes by id, year, byline-slug, and kind.
 *
 * Runs in the browser at runtime by fetching JSON over HTTP. Build-time
 * prerender entry generators use the server-only loaders in $lib/server/data.
 */
import type { Dataset, Entry, Graphic, Podcast } from './types';
import { base } from '$app/paths';

export interface DataCache {
	all: Entry[];
	byId: Map<string, Entry>;
	byYear: Map<number, Entry[]>;
	byYearMonth: Map<string, Entry[]>; // key: "YYYY-MM"
	byBylineSlug: Map<string, { name: string; entries: Entry[] }>;
	years: number[];
	/** Sorted list of YYYY-MM keys per year, e.g. monthsByYear.get(2020) → ["2020-01", "2020-02", …]. */
	monthsByYear: Map<number, string[]>;
}

const MONTH_LABELS: Record<string, string> = {
	'01': 'January',
	'02': 'February',
	'03': 'March',
	'04': 'April',
	'05': 'May',
	'06': 'June',
	'07': 'July',
	'08': 'August',
	'09': 'September',
	'10': 'October',
	'11': 'November',
	'12': 'December'
};

export function monthLabel(mm: string): string {
	return MONTH_LABELS[mm] ?? mm;
}

let cache: DataCache | null = null;

export interface DatasetCache {
	all: Dataset[];
	bySlug: Map<string, Dataset>;
}

let datasetCache: DatasetCache | null = null;

export interface PodcastCache {
	all: Podcast[];
	bySeriesSlug: Map<string, { name: string; podcasts: Podcast[] }>;
	series: { slug: string; name: string; count: number }[];
}

let podcastCache: PodcastCache | null = null;

export interface GraphicCache {
	all: Graphic[];
	byYear: Map<number, Graphic[]>;
	byYearMonth: Map<string, Graphic[]>; // key: "YYYY-MM"
	years: number[];
	/** Sorted list of YYYY-MM keys per year, e.g. monthsByYear.get(2020) → ["2020-01", "2020-02", …]. */
	monthsByYear: Map<number, string[]>;
	categories: { slug: string; name: string; count: number }[];
}

let graphicCache: GraphicCache | null = null;
let illustrationCache: GraphicCache | null = null;

const DIACRITICS = /[̀-ͯ]/g;

export function slugify(text: string): string {
	if (!text) return '';
	return text
		.normalize('NFKD')
		.replace(DIACRITICS, '')
		.toLowerCase()
		.replace(/[^a-z0-9]+/g, '-')
		.replace(/^-+|-+$/g, '');
}

async function fetchEntries(fetcher: typeof fetch): Promise<Entry[]> {
	const resp = await fetcher(`${base}/data/articles.json`);
	if (!resp.ok) throw new Error(`failed to load articles.json: ${resp.status}`);
	return resp.json();
}

async function fetchDatasets(fetcher: typeof fetch): Promise<Dataset[]> {
	const resp = await fetcher(`${base}/data/datasets.json`);
	if (!resp.ok) throw new Error(`failed to load datasets.json: ${resp.status}`);
	return resp.json();
}

async function fetchPodcasts(fetcher: typeof fetch): Promise<Podcast[]> {
	const resp = await fetcher(`${base}/data/podcasts.json`);
	if (!resp.ok) throw new Error(`failed to load podcasts.json: ${resp.status}`);
	return resp.json();
}

async function fetchGraphics(fetcher: typeof fetch): Promise<Graphic[]> {
	const resp = await fetcher(`${base}/data/graphics.json`);
	if (!resp.ok) throw new Error(`failed to load graphics.json: ${resp.status}`);
	return resp.json();
}

async function fetchIllustrations(fetcher: typeof fetch): Promise<Graphic[]> {
	const resp = await fetcher(`${base}/data/illustrations.json`);
	if (!resp.ok) throw new Error(`failed to load illustrations.json: ${resp.status}`);
	return resp.json();
}

export async function loadEntries(fetcher?: typeof fetch): Promise<DataCache> {
	if (cache) return cache;

	const all = await fetchEntries(fetcher ?? fetch);
	cache = buildEntryCache(all);
	return cache;
}

export function buildEntryCache(all: Entry[]): DataCache {
	const byId = new Map<string, Entry>();
	const byYear = new Map<number, Entry[]>();
	const byYearMonth = new Map<string, Entry[]>();
	const byBylineSlug = new Map<string, { name: string; entries: Entry[] }>();

	for (const entry of all) {
		byId.set(entry.id, entry);

		if (entry.year != null) {
			let arr = byYear.get(entry.year);
			if (!arr) {
				arr = [];
				byYear.set(entry.year, arr);
			}
			arr.push(entry);

			// `date` is either an ISO timestamp, YYYY-MM-DD, or YYYY-MM.
			// Only bucket by month when we have at least YYYY-MM precision.
			const ym = entry.date && entry.date.length >= 7 ? entry.date.slice(0, 7) : null;
			if (ym && /^\d{4}-\d{2}$/.test(ym)) {
				let bucket = byYearMonth.get(ym);
				if (!bucket) {
					bucket = [];
					byYearMonth.set(ym, bucket);
				}
				bucket.push(entry);
			}
		}

		for (const author of entry.authors) {
			const slug = slugify(author);
			if (!slug) continue;
			let bucket = byBylineSlug.get(slug);
			if (!bucket) {
				bucket = { name: author, entries: [] };
				byBylineSlug.set(slug, bucket);
			}
			bucket.entries.push(entry);
		}
	}

	// Oldest year first — this is a chronological retrospective.
	const years = [...byYear.keys()].sort((a, b) => a - b);

	// Per-year ordered list of YYYY-MM keys, ascending.
	const monthsByYear = new Map<number, string[]>();
	for (const ym of byYearMonth.keys()) {
		const year = Number(ym.slice(0, 4));
		let arr = monthsByYear.get(year);
		if (!arr) {
			arr = [];
			monthsByYear.set(year, arr);
		}
		arr.push(ym);
	}
	for (const arr of monthsByYear.values()) arr.sort();

	return { all, byId, byYear, byYearMonth, byBylineSlug, years, monthsByYear };
}

export async function loadDatasets(fetcher?: typeof fetch): Promise<DatasetCache> {
	if (datasetCache) return datasetCache;

	const all = await fetchDatasets(fetcher ?? fetch);
	datasetCache = buildDatasetCache(all);
	return datasetCache;
}

export function buildDatasetCache(all: Dataset[]): DatasetCache {
	const bySlug = new Map<string, Dataset>();
	for (const dataset of all) {
		bySlug.set(dataset.slug, dataset);
	}

	return { all, bySlug };
}

export async function loadPodcasts(fetcher?: typeof fetch): Promise<PodcastCache> {
	if (podcastCache) return podcastCache;

	const all = await fetchPodcasts(fetcher ?? fetch);
	podcastCache = buildPodcastCache(all);
	return podcastCache;
}

export function buildPodcastCache(all: Podcast[]): PodcastCache {
	const bySeriesSlug = new Map<string, { name: string; podcasts: Podcast[] }>();
	for (const podcast of all) {
		const slug = podcast.series_slug;
		if (!slug) continue;
		let bucket = bySeriesSlug.get(slug);
		if (!bucket) {
			bucket = { name: podcast.series, podcasts: [] };
			bySeriesSlug.set(slug, bucket);
		}
		bucket.podcasts.push(podcast);
	}

	const series = [...bySeriesSlug.entries()]
		.map(([slug, { name, podcasts }]) => ({ slug, name, count: podcasts.length }))
		.sort((a, b) => b.count - a.count || a.name.localeCompare(b.name));

	return { all, bySeriesSlug, series };
}

export async function loadGraphics(fetcher?: typeof fetch): Promise<GraphicCache> {
	if (graphicCache) return graphicCache;

	const all = await fetchGraphics(fetcher ?? fetch);
	graphicCache = buildGraphicCache(all);
	return graphicCache;
}

export async function loadIllustrations(fetcher?: typeof fetch): Promise<GraphicCache> {
	if (illustrationCache) return illustrationCache;

	const all = await fetchIllustrations(fetcher ?? fetch);
	illustrationCache = buildGraphicCache(all, [
		{ slug: 'artistic-illustration', name: 'Illustrations', count: all.length }
	]);
	return illustrationCache;
}

export function buildGraphicCache(
	all: Graphic[],
	overrideCategories?: { slug: string; name: string; count: number }[]
): GraphicCache {
	const byCategory = new Map<string, { name: string; count: number }>();
	const byYear = new Map<number, Graphic[]>();
	const byYearMonth = new Map<string, Graphic[]>();
	const monthsByYear = new Map<number, Set<string>>();

	for (const graphic of all) {
		const slug = graphicCategoryGroup(graphic.category);
		const current = byCategory.get(slug);
		if (current) {
			current.count += 1;
		} else {
			byCategory.set(slug, { name: categoryLabel(slug), count: 1 });
		}

		if (graphic.year !== null) {
			const yearBucket = byYear.get(graphic.year) ?? [];
			yearBucket.push(graphic);
			byYear.set(graphic.year, yearBucket);

			const month = graphic.date.match(/^(\d{4})-(\d{2})/)?.[0];
			if (month && Number(month.slice(0, 4)) === graphic.year) {
				const monthBucket = byYearMonth.get(month) ?? [];
				monthBucket.push(graphic);
				byYearMonth.set(month, monthBucket);

				const months = monthsByYear.get(graphic.year) ?? new Set<string>();
				months.add(month);
				monthsByYear.set(graphic.year, months);
			}
		}
	}
	const categories = (
		overrideCategories
			? overrideCategories.filter((category) => category.count > 0)
			: [...byCategory.entries()].map(([slug, { name, count }]) => ({ slug, name, count }))
	).sort(compareGraphicCategories);

	return {
		all,
		byYear,
		byYearMonth,
		years: [...byYear.keys()].sort((a, b) => a - b),
		monthsByYear: new Map(
			[...monthsByYear.entries()].map(([year, months]) => [year, [...months].sort()])
		),
		categories
	};
}

function compareGraphicCategories(
	a: { slug: string; name: string },
	b: { slug: string; name: string }
): number {
	if (a.slug === 'infographic' && b.slug !== 'infographic') return 1;
	if (b.slug === 'infographic' && a.slug !== 'infographic') return -1;
	return a.name.localeCompare(b.name);
}

export function graphicCategoryGroup(category: string): string {
	const groups: Record<string, string> = {
		'chart-screenshot': 'chart'
	};
	return groups[category] ?? category;
}

export function categoryLabel(category: string): string {
	const labels: Record<string, string> = {
		'chart': 'Charts',
		'chart-screenshot': 'Charts',
		'html-bundle': 'HTML bundles',
		'infographic': 'Other',
		'artistic-illustration': 'Illustrations',
		'map': 'Maps',
		'table': 'Tables'
	};
	return labels[category] ?? category;
}
